    {
        serverErrors.Clear();

        var errors = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor ?? "",
            Model.TimeSlot ?? "");

        if (errors.Count > 0)
        {
            serverErrors = errors;
            return;
        }

        submitted = true;
    }

    private void GoBackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
    }

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }
}

