arguments.new_str:
private async Task HandleSubmit()
{
    serverErrors.Clear();
    submitted = false;

    // Validate step 2 required fields
    bool step2Valid = true;
    if (string.IsNullOrWhiteSpace(Model.Doctor))
    {
        serverErrors["Doctor"] = "Please select a doctor";
        step2Valid = false;
    }
    if (!Model.AppointmentDate.HasValue)
    {
        serverErrors["Date"] = "Please select a date";
        step2Valid = false;
    }
    if (string.IsNullOrWhiteSpace(Model.TimeSlot))
    {
        serverErrors["TimeSlot"] = "Please select a time slot";
        step2Valid = false;
    }
    if (string.IsNullOrWhiteSpace(Model.ReasonForVisit))
    {
        serverErrors["Reason"] = "Reason for visit is required";
        step2Valid = false;
    }

    if (!step2Valid)
        return;

    var errors = await AppointmentService.ValidatePatientAsync(
        Model.Email,
        Model.InsuranceProvider,
        Model.Doctor ?? "",
        Model.TimeSlot ?? "");

    if (errors.Count > 0)
    {
        serverErrors = errors;
        return;
    }

    submitted = true;
}

